j=b2.fV("1. Ko\u015fullar\u0131n Kabul\xfc",'Bulmacam\'a ho\u015f geldiniz. Bu Kullan\u0131m Ko\u015fullar\u0131 ("Ko\u015fullar"), Bulmacam mobil uygulamas\u0131na ("Uygulama," "Hizmet," ya da "biz/bize/bizim") eri\u015fiminizi ve kullan\u0131m\u0131n\u0131z\u0131 d\xfczenler. Uygulamay\u0131 indirerek, y\xfckleyerek, ona eri\u015ferek veya onu kullanarak; bu Ko\u015fullar\u0131 okudu\u011funuzu, anlad\u0131\u011f\u0131n\u0131z\u0131 ve onlara ba\u011fl\u0131 kalmay\u0131 kabul etti\u011finizi beyan etmi\u015f olursunuz.\n\nBu Ko\u015fullar\u0131 kabul etmiyorsan\u0131z, Uygulamay\u0131 indirmemeli, y\xfcklememeli veya kullanmamal\u0131s\u0131n\u0131z. Herhangi bir zamanda, herhangi bir nedenle herhangi birine hizmet vermeyi reddetme hakk\u0131m\u0131z sakl\u0131d\u0131r.',p,o)
i=b2.fV("2. Hizmetin Tan\u0131m\u0131","Bulmacam, \u015funlar\u0131 sunan bir kelime bulmaca oyunu uygulamas\u0131d\u0131r:\n\u2022 \xdc\xe7 g\xfcnl\xfck kelime bulmaca modu: Klasik, Anlam ve K\xf6pr\xfc\n\u2022 Yerel saat diliminizde gece yar\u0131s\u0131 s\u0131f\u0131rlanan g\xfcnl\xfck bulmacalar\n\u2022 Oyun istatistiklerinin, ilerlemenin ve serilerin yerel olarak saklanmas\u0131\n\u2022 \xc7evrimd\u0131\u015f\u0131 oynanabilme imk\xe2n\u0131\n\nUygulama, ki\u015fisel e\u011flence amac\u0131yla tasarlanm\u0131\u015ft\u0131r ve temel oyun i\u015flevleri i\xe7in hesap olu\u015fturma veya internet ba\u011flant\u0131s\u0131 gerektirmez.",p,o)
h=b2.fV("3. Uygunluk","Bulmacam her ya\u015f (4+) i\xe7in derecelendirilmi\u015ftir ve genel bir kitleye uygundur. 18 ya\u015f\u0131n alt\u0131ndaysan\u0131z, ebeveyninizin veya yasal vasinizin bu Ko\u015fullar\u0131 sizin ad\u0131n\u0131za inceledi\u011fini ve kabul etti\u011fini beyan edersiniz.",p,o)
g=b2.fV("4. Kabul Edilebilir Kullan\u0131m",'Uygulamay\u0131 yaln\u0131zca yasal ama\xe7larla ve bu Ko\u015fullara uygun olarak kullanmay\u0131 kabul edersiniz. \u015eunlar\u0131 YAPMAMAYI kabul edersiniz:\n\n\u2022 Uygulamay\u0131, y\xfcr\xfcrl\xfckteki herhangi bir federal, eyalet, yerel veya uluslararas\u0131 yasay\u0131 ya da d\xfczenlemeyi ihlal edecek \u015fekilde kullanmak\n\u2022 Uygulaman\u0131n veya ilgili herhangi bir sistem ya da a\u011f\u0131n a\xe7\u0131klar\u0131n\u0131 yoklamaya, taramaya veya test etmeye kalk\u0131\u015fmak\n\u2022 Uygulaman\u0131n kaynak kodunu tersine m\xfchendislikle \xe7\xf6zmeye, kaynak koda d\xf6n\xfc\u015ft\xfcrmeye, par\xe7alar\u0131na ay\u0131rmaya veya ba\u015fka bir yolla ke\u015ffetmeye kalk\u0131\u015fmak\n\u2022 Uygulamay\u0131 temel alan de\u011fi\u015fiklikler yapmak, uyarlamak, \xe7evirmek veya t\xfcrev \xe7al\u0131\u015fmalar olu\u015fturmak\n\u2022 Uygulama \xfczerindeki herhangi bir m\xfclkiyet bildirimini, etiketi ya da i\u015fareti kald\u0131rmak, de\u011fi\u015ftirmek veya gizlemek\n\u2022 Uygulamaya eri\u015fmek i\xe7in "robotlar," "\xf6r\xfcmcekler" ya da "\xe7evrimd\u0131\u015f\u0131 okuyucular" d\xe2hil ancak bunlarla s\u0131n\u0131rl\u0131 olmaks\u0131z\u0131n herhangi bir otomatik sistem kullanmak\n\u2022 Uygulamay\u0131 \xe7al\u0131\u015ft\u0131ran sunuculara giden veya onlardan gelen herhangi bir iletime m\xfcdahale etmeye, sistem b\xfct\xfcnl\xfc\u011f\xfcn\xfc ya da g\xfcvenli\u011fini tehlikeye atmaya veya bu iletimleri \xe7\xf6zmeye kalk\u0131\u015fmak\n\u2022 \xd6nceden yaz\u0131l\u0131 iznimiz olmaks\u0131z\u0131n Uygulamay\u0131 herhangi bir ticari ama\xe7la kullanmak\n\u2022 Uygulamay\u0131 yeniden da\u011f\u0131tmak, alt lisanslamak, kiralamak, yay\u0131mlamak, satmak, devretmek, kiraya vermek, pazarlamak, aktarmak veya ba\u015fka bir yolla \xfc\xe7\xfcnc\xfc taraflara sunmak',p,o)
f=b2.fV("5. Fikr\xee M\xfclkiyet Haklar\u0131","Uygulama ve onun t\xfcm i\xe7eri\u011fi, \xf6zellikleri ve i\u015flevselli\u011fi (t\xfcm bilgiler, yaz\u0131l\u0131m, kod, metin, g\xf6r\xfcnt\xfcler, grafikler, foto\u011fraflar, video, ses, tasar\u0131m, sunum, se\xe7im ve d\xfczenleme d\xe2hil ancak bunlarla s\u0131n\u0131rl\u0131 olmaks\u0131z\u0131n) Bulmacam'a, lisans verenlerine veya bu t\xfcr materyallerin di\u011fer sa\u011flay\u0131c\u0131lar\u0131na aittir ve Amerika Birle\u015fik Devletleri ile uluslararas\u0131 telif hakk\u0131, ticari marka, patent, ticari s\u0131r ve di\u011fer fikr\xee m\xfclkiyet ya da m\xfclkiyet haklar\u0131 yasalar\u0131yla korunmaktad\u0131r.\n\n\"Bulmacam\" ad\u0131, Uygulama logosu ve ilgili t\xfcm adlar, logolar, \xfcr\xfcn ve hizmet adlar\u0131, tasar\u0131mlar ve sloganlar Bulmacam'\u0131n ya da ba\u011fl\u0131 kurulu\u015flar\u0131n\u0131n veya lisans verenlerinin ticari markalar\u0131d\u0131r. Bu i\u015faretleri Bulmacam'\u0131n \xf6nceden yaz\u0131l\u0131 izni olmadan kullanamazs\u0131n\u0131z.\n\nUygulama i\xe7inde yer alan kelime listeleri, bulmaca algoritmalar\u0131, oyun mekanikleri, g\xf6rsel tasar\u0131m \xf6\u011feleri ve kullan\u0131c\u0131 aray\xfcz\xfc bile\u015fenleri \xf6zel ve gizlidir.\n\nBu Ko\u015fullar, Uygulamay\u0131 bu Ko\u015fullara uygun olarak ki\u015fisel, ticari olmayan ama\xe7larla kullanman\u0131z i\xe7in verilen s\u0131n\u0131rl\u0131, m\xfcnhas\u0131r olmayan, devredilemez ve iptal edilebilir bir lisans d\u0131\u015f\u0131nda, size Uygulama \xfczerinde herhangi bir hak, m\xfclkiyet veya menfaat tan\u0131maz.",p,o)
e=b2.fV("6. Kullan\u0131c\u0131 Verileri ve Gizlilik","Oyun ilerlemeniz, istatistikleriniz, ba\u015far\u0131mlar\u0131n\u0131z ve tercihleriniz cihaz\u0131n\u0131zda yerel olarak saklan\u0131r. Ki\u015fisel verilerinizi harici sunucularda toplamaz, iletmez veya saklamay\u0131z. Veri uygulamalar\u0131m\u0131z hakk\u0131nda ayr\u0131nt\u0131l\u0131 bilgi i\xe7in l\xfctfen Gizlilik Politikam\u0131za ba\u015fvurun.\n\n\u015eunlar\u0131 kabul ve beyan edersiniz:\n\u2022 Cihaz verilerinizin yedeklerini almaktan yaln\u0131zca siz sorumlusunuz\n\u2022 Cihaz ar\u0131zas\u0131, Uygulaman\u0131n silinmesi, i\u015fletim sistemi g\xfcncellemeleri veya ba\u015fka herhangi bir durum nedeniyle olu\u015fan oyun verisi kay\u0131plar\u0131ndan sorumlu de\u011filiz\n\u2022 Cihaz\u0131n\u0131z\u0131n yerle\u015fik yedekleme ve geri y\xfckleme i\u015flevini kullanmad\u0131\u011f\u0131n\u0131z s\xfcrece oyun ilerlemesi ve istatistikleri cihazlar aras\u0131nda aktar\u0131lamaz",p,o)
d=b2.fV("7. G\xfcncellemeler ve De\u011fi\u015fiklikler","\u015eunlar\u0131 yapma hakk\u0131m\u0131z sakl\u0131d\u0131r:\n\n\u2022 Uygulamay\u0131 (veya herhangi bir b\xf6l\xfcm\xfcn\xfc) herhangi bir zamanda bildirimde bulunmaks\u0131z\u0131n de\u011fi\u015ftirmek, g\xfcncellemek veya durdurmak\n\u2022 Kendi takdirimize ba\u011fl\u0131 olarak \xf6zellikler, oyun modlar\u0131 veya i\xe7erik eklemek, de\u011fi\u015ftirmek ya da kald\u0131rmak\n\u2022 Uygulaman\u0131n kullan\u0131lmaya devam edilmesi i\xe7in gerekebilecek g\xfcncellemeleri yay\u0131mlamak\n\u2022 G\xfcnl\xfck bulmaca takvimini veya s\u0131f\u0131rlama mekaniklerini de\u011fi\u015ftirmek\n\nHerhangi bir g\xfcncelleme sa\u011flama ya da Uygulaman\u0131n belirli \xf6zelliklerini veya i\u015flevlerini sunmaya veya etkin tutmaya devam etme y\xfck\xfcml\xfcl\xfc\u011f\xfcm\xfcz\xfcn bulunmad\u0131\u011f\u0131n\u0131 kabul edersiniz.",p,o)
c=b2.fV("8. \xdc\xe7\xfcnc\xfc Taraf Hizmetleri","Uygulama, Bulmacam'a ait olmayan veya onun taraf\u0131ndan denetlenmeyen \xfc\xe7\xfcnc\xfc taraf web sitelerine ya da hizmetlerine ba\u011flant\u0131lar i\xe7erebilir. Herhangi bir \xfc\xe7\xfcnc\xfc taraf web sitesinin veya hizmetinin i\xe7eri\u011fi, gizlilik politikalar\u0131 ya da uygulamalar\u0131 \xfczerinde hi\xe7bir denetimimiz yoktur ve bunlardan hi\xe7bir sorumluluk \xfcstlenmeyiz.\n\nBu t\xfcr web sitelerinde veya hizmetlerinde ya da bunlar arac\u0131l\u0131\u011f\u0131yla sunulan herhangi bir i\xe7eri\u011fin, mal\u0131n veya hizmetin kullan\u0131m\u0131ndan ya da bunlara g\xfcvenilmesinden kaynaklanan veya kaynakland\u0131\u011f\u0131 iddia edilen herhangi bir zarar veya kay\u0131ptan Bulmacam'\u0131n do\u011frudan ya da dolayl\u0131 olarak sorumlu tutulamayaca\u011f\u0131n\u0131 kabul ve beyan edersiniz.",p,o)
b=b2.fV("9. Garantilerin Reddi",'UYGULAMA, A\xc7IK YA DA ZIMN\u0130 HERHANG\u0130 B\u0130R T\xdcRDE GARANT\u0130 VER\u0130LMEKS\u0130Z\u0130N, "OLDU\u011eU G\u0130B\u0130" VE "MEVCUT OLDU\u011eU H\xc2L\u0130YLE" SUNULMAKTADIR. NE BULMACAM NE DE BULMACAM \u0130LE BA\u011eLANTILI HERHANG\u0130 B\u0130R K\u0130\u015e\u0130, UYGULAMANIN EKS\u0130KS\u0130ZL\u0130\u011e\u0130, G\xdcVENL\u0130\u011e\u0130, G\xdcVEN\u0130L\u0130RL\u0130\u011e\u0130, KAL\u0130TES\u0130, DO\u011eRULU\u011eU YA DA KULLANILAB\u0130L\u0130RL\u0130\u011e\u0130 KONUSUNDA HERHANG\u0130 B\u0130R GARANT\u0130 VEYA BEYANDA BULUNMAZ.\n\nYUKARIDAK\u0130LER\u0130 SINIRLAMAKSIZIN, NE BULMACAM NE DE BULMACAM \u0130LE BA\u011eLANTILI HERHANG\u0130 B\u0130R\u0130; UYGULAMANIN DO\u011eRU, G\xdcVEN\u0130L\u0130R, HATASIZ YA DA KES\u0130NT\u0130S\u0130Z OLACA\u011eINI, KUSURLARIN G\u0130DER\u0130LECE\u011e\u0130N\u0130, UYGULAMANIN VEYA ONU SUNAN SUNUCUNUN V\u0130R\xdcSLERDEN YA DA D\u0130\u011eER ZARARLI B\u0130LE\u015eENLERDEN ARINDIRILMI\u015e OLDU\u011eUNU VEYA UYGULAMANIN \u0130HT\u0130YA\xc7LARINIZI YA DA BEKLENT\u0130LER\u0130N\u0130Z\u0130 KAR\u015eILAYACA\u011eINI BEYAN YA DA GARANT\u0130 ETMEZ.\n\nYASANIN \u0130Z\u0130N VERD\u0130\u011e\u0130 EN GEN\u0130\u015e \xd6L\xc7\xdcDE, BULMACAM \u0130\u015eBU BELGEYLE; SATILAB\u0130L\u0130RL\u0130K, \u0130HLAL ETMEME VE BEL\u0130RL\u0130 B\u0130R AMACA UYGUNLUK GARANT\u0130LER\u0130 D\xc2H\u0130L ANCAK BUNLARLA SINIRLI OLMAKSIZIN, A\xc7IK YA DA ZIMN\u0130, YASAL VEYA BA\u015eKA T\xdcRL\xdc HER T\xdcRDE T\xdcM GARANT\u0130LER\u0130 REDDEDER.',p,o)
a=b2.fV("10. Sorumlulu\u011fun S\u0131n\u0131rland\u0131r\u0131lmas\u0131","Y\xdcR\xdcRL\xdcKTEK\u0130 YASANIN \u0130Z\u0130N VERD\u0130\u011e\u0130 EN GEN\u0130\u015e \xd6L\xc7\xdcDE, BULMACAM, BA\u011eLI KURULU\u015eLARI YA DA ONLARIN L\u0130SANS VERENLER\u0130, H\u0130ZMET SA\u011eLAYICILARI, \xc7ALI\u015eANLARI, TEMS\u0130LC\u0130LER\u0130, YETK\u0130L\u0130LER\u0130 VEYA Y\xd6NET\u0130C\u0130LER\u0130; UYGULAMAYI KULLANMANIZDAN YA DA KULLANAMAMANIZDAN KAYNAKLANAN VEYA BUNUNLA BA\u011eLANTILI OLARAK, HERHANG\u0130 B\u0130R HUKUK\u0130 DAYANAK ALTINDA, HERHANG\u0130 B\u0130R DO\u011eRUDAN, DOLAYLI, \xd6ZEL, ARIZ\u0130, SONU\xc7SAL VEYA CEZA\u0130 ZARAR D\xc2H\u0130L ANCAK BUNLARLA SINIRLI OLMAKSIZIN, H\u0130\xc7B\u0130R DURUMDA H\u0130\xc7B\u0130R T\xdcRDE ZARARDAN SORUMLU OLMAYACAKTIR; BUNLARA \u015eUNLAR D\xc2H\u0130LD\u0130R:\n\n\u2022 Ki\u015fisel yaralanma veya maddi hasar\n\u2022 Gelir, k\xe2r, i\u015f ya da \xf6ng\xf6r\xfclen tasarruf kayb\u0131\n\u2022 Kullan\u0131m, itibar veya veri kayb\u0131\n\u2022 Di\u011fer her t\xfcrl\xfc maddi olmayan kay\u0131p\n\nBU; HAKSIZ F\u0130\u0130LDEN (\u0130HMAL D\xc2H\u0130L), S\xd6ZLE\u015eMEN\u0130N \u0130HLAL\u0130NDEN VEYA BA\u015eKA B\u0130R NEDENDEN KAYNAKLANSIN, \xd6NG\xd6R\xdcLEB\u0130L\u0130R OLSA DAH\u0130 GE\xc7ERL\u0130D\u0130R.\n\nYUKARIDAK\u0130LER, Y\xdcR\xdcRL\xdcKTEK\u0130 YASA UYARINCA HAR\u0130\xc7 TUTULAMAYAN VEYA SINIRLANDIRILAMAYAN HERHANG\u0130 B\u0130R SORUMLULU\u011eU ETK\u0130LEMEZ.",p,o)
a0=b2.fV("11. Tazminat","Bu Ko\u015fullar\u0131 ihlal etmenizden veya Uygulamay\u0131 kullanman\u0131zdan kaynaklanan ya da bunlarla ilgili olan herhangi bir talep, y\xfck\xfcml\xfcl\xfck, zarar, mahkeme karar\u0131, h\xfck\xfcm, kay\u0131p, maliyet, masraf veya \xfccret (makul avukatl\u0131k \xfccretleri d\xe2hil) kar\u015f\u0131s\u0131nda; Bulmacam'\u0131, ba\u011fl\u0131 kurulu\u015flar\u0131n\u0131, lisans verenlerini ve hizmet sa\u011flay\u0131c\u0131lar\u0131n\u0131 ve bunlar\u0131n ilgili yetkililerini, y\xf6neticilerini, \xe7al\u0131\u015fanlar\u0131n\u0131, y\xfcklenicilerini, temsilcilerini, lisans verenlerini, tedarik\xe7ilerini, haleflerini ve devralanlar\u0131n\u0131 savunmay\u0131, tazmin etmeyi ve zarardan korumay\u0131 kabul edersiniz.",p,o)
a1=b2.fV("12. Fesih","Bu Ko\u015fullar\u0131 ihlal etmeniz d\xe2hil ancak bununla s\u0131n\u0131rl\u0131 olmaks\u0131z\u0131n, herhangi bir nedenle, \xf6nceden bildirimde bulunmaks\u0131z\u0131n veya herhangi bir y\xfck\xfcml\xfcl\xfck alt\u0131na girmeksizin Uygulamaya eri\u015fiminizi derhal sonland\u0131rabilir veya ask\u0131ya alabiliriz.\n\nFesih \xfczerine, Uygulamay\u0131 kullanma hakk\u0131n\u0131z derhal sona erer. Bu Ko\u015fullar\u0131n, nitelikleri gere\u011fi fesihten sonra da y\xfcr\xfcrl\xfckte kalmas\u0131 gereken t\xfcm h\xfck\xfcmleri; m\xfclkiyet h\xfck\xfcmleri, garanti reddi, tazminat ve sorumluluk s\u0131n\u0131rlamalar\u0131 d\xe2hil ancak bunlarla s\u0131n\u0131rl\u0131 olmaks\u0131z\u0131n, fesihten sonra da y\xfcr\xfcrl\xfckte kal\u0131r.\n\nUygulamay\u0131 cihaz\u0131n\u0131zdan silerek kullan\u0131m\u0131n\u0131z\u0131 istedi\u011finiz zaman sonland\u0131rabilirsiniz.",p,o)
a2=b2.fV("13. Ge\xe7erli Hukuk ve Uyu\u015fmazl\u0131k \xc7\xf6z\xfcm\xfc","Bu Ko\u015fullar, kanunlar ihtilaf\u0131 h\xfck\xfcmleri dikkate al\u0131nmaks\u0131z\u0131n, Amerika Birle\u015fik Devletleri Delaware Eyaleti yasalar\u0131na g\xf6re y\xf6netilir ve yorumlan\u0131r.\n\nBu Ko\u015fullardan veya Uygulamadan kaynaklanan ya da bunlarla ilgili herhangi bir hukuki dava, i\u015flem veya yarg\u0131lama, m\xfcnhas\u0131ran Amerika Birle\u015fik Devletleri federal mahkemelerinde veya Delaware Eyaleti mahkemelerinde a\xe7\u0131lacakt\u0131r. Bu mahkemelerin \xfczerinizdeki yarg\u0131 yetkisini kullanmas\u0131na ve bu mahkemelerin yetkili yarg\u0131 yeri olmas\u0131na ili\u015fkin her t\xfcrl\xfc itirazdan feragat edersiniz.\n\nBu Ko\u015fullardan kaynaklanan her t\xfcrl\xfc uyu\u015fmazl\u0131k, American Arbitration Association kurallar\u0131na uygun olarak ba\u011flay\u0131c\u0131 tahkim yoluyla \xe7\xf6z\xfcl\xfcr; ancak talepleriniz uygunsa bunlar\u0131 k\xfc\xe7\xfck talepler mahkemesinde de ileri s\xfcrebilirsiniz.",p,o)
a3=b2.fV("14. Ko\u015fullardaki De\u011fi\u015fiklikler","Bu Ko\u015fullar\u0131 herhangi bir zamanda, yaln\u0131zca kendi takdirimize ba\u011fl\u0131 olarak de\u011fi\u015ftirme veya yenisiyle de\u011fi\u015ftirme hakk\u0131m\u0131z sakl\u0131d\u0131r. Bir de\u011fi\u015fiklik esasl\u0131 nitelikteyse, yeni ko\u015fullar y\xfcr\xfcrl\xfc\u011fe girmeden \xf6nce en az 30 g\xfcn \xf6nceden bildirimde bulunmak i\xe7in makul \xe7abay\u0131 g\xf6sterece\u011fiz. Neyin esasl\u0131 bir de\u011fi\u015fiklik te\u015fkil etti\u011fi yaln\u0131zca kendi takdirimize g\xf6re belirlenir.\n\nBu de\u011fi\u015fiklikler y\xfcr\xfcrl\xfc\u011fe girdikten sonra Uygulamaya eri\u015fmeye veya onu kullanmaya devam ederek, de\u011fi\u015ftirilmi\u015f ko\u015fullara ba\u011fl\u0131 kalmay\u0131 kabul edersiniz. Yeni ko\u015fullar\u0131 tamamen ya da k\u0131smen kabul etmiyorsan\u0131z, l\xfctfen Uygulamay\u0131 kullanmay\u0131 b\u0131rak\u0131n.",p,o)
a4=b2.fV("15. B\xf6l\xfcnebilirlik","Bu Ko\u015fullar\u0131n herhangi bir h\xfckm\xfcn\xfcn uygulanamaz veya ge\xe7ersiz oldu\u011funa karar verilirse, s\xf6z konusu h\xfck\xfcm, y\xfcr\xfcrl\xfckteki yasa kapsam\u0131nda m\xfcmk\xfcn olan en geni\u015f \xf6l\xe7\xfcde o h\xfckm\xfcn ama\xe7lar\u0131n\u0131 ger\xe7ekle\u015ftirecek \u015fekilde de\u011fi\u015ftirilir ve yorumlan\u0131r; geri kalan h\xfck\xfcmler ise t\xfcm g\xfc\xe7 ve etkisiyle y\xfcr\xfcrl\xfckte kalmaya devam eder.",p,o)
a5=b2.fV("16. Feragat","Bulmacam'\u0131n bu Ko\u015fullarda belirtilen herhangi bir \u015fart ya da ko\u015fuldan feragat etmesi, s\xf6z konusu \u015fart veya ko\u015fuldan ileriye d\xf6n\xfck ya da s\xfcregelen bir feragat veya ba\u015fka herhangi bir \u015fart ya da ko\u015fuldan feragat say\u0131lmaz; Bulmacam'\u0131n bu Ko\u015fullar kapsam\u0131ndaki bir hakk\u0131 ya da h\xfckm\xfc ileri s\xfcrmemesi de s\xf6z konusu hak veya h\xfck\xfcmden feragat anlam\u0131na gelmez.",p,o)
a6=b2.fV("17. S\xf6zle\u015fmenin Tamam\u0131","Bu Ko\u015fullar, Gizlilik Politikam\u0131zla birlikte, Uygulamaya ili\u015fkin olarak sizinle Bulmacam aras\u0131ndaki yeg\xe2ne ve eksiksiz s\xf6zle\u015fmeyi olu\u015fturur ve Uygulamaya ili\u015fkin \xf6nceki ve e\u015f zamanl\u0131 t\xfcm yaz\u0131l\u0131 ve s\xf6zl\xfc mutabakatlar\u0131n, s\xf6zle\u015fmelerin, beyanlar\u0131n ve garantilerin yerini al\u0131r.",p,o)
a7=b2.fV("18. \u0130leti\u015fim Bilgileri","Bu Kullan\u0131m Ko\u015fullar\u0131 hakk\u0131nda herhangi bir sorunuz varsa, l\xfctfen Uygulamada bulunan destek se\xe7enekleri arac\u0131l\u0131\u011f\u0131yla bizimle ileti\u015fime ge\xe7in veya g\xfcncel ileti\u015fim bilgileri i\xe7in web sitemizi ziyaret edin.",p,o)
